import React, { useState } from 'react';
import { Menu, X, ChevronDown } from 'lucide-react';

const Header = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  const toggleDropdown = () => {
    setIsDropdownOpen(!isDropdownOpen);
  };

  return (
    <header className="header">
      <div className="header-container">
        <div className="header-left">
          <div className="logo">
            <span className="logo-text">Lrnsy</span>
          </div>
          <nav className="nav-menu">
            <a href="#why" className="nav-link">Why Lrnsy Exists</a>
            <div className="nav-dropdown">
              <button className="nav-link dropdown-toggle" onClick={toggleDropdown}>
                System <ChevronDown size={16} />
              </button>
              {isDropdownOpen && (
                <div className="dropdown-menu">
                  <a href="#learner-intelligence" className="dropdown-item">Learner Intelligence</a>
                  <a href="#school-intelligence" className="dropdown-item">School Intelligence</a>
                  <a href="#continuous-alignment" className="dropdown-item">Continuous Alignment</a>
                  <a href="#how-it-applied" className="dropdown-item">How It Is Applied</a>
                </div>
              )}
            </div>
            <a href="#integration" className="nav-link">Integration Levels</a>
            <a href="#research" className="nav-link">Research and Evidence</a>
            <a href="#faq" className="nav-link">FAQ</a>
            <a href="#contact" className="nav-link">Contact</a>
          </nav>
        </div>
        <div className="header-right">
          <a href="#login" className="login-btn">Login</a>
          <button className="mobile-menu-btn" onClick={toggleMenu}>
            {isMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
      </div>
      {isMenuOpen && (
        <div className="mobile-menu">
          <a href="#why" className="mobile-nav-link">Why Lrnsy Exists</a>
          <a href="#system" className="mobile-nav-link">System</a>
          <a href="#integration" className="mobile-nav-link">Integration Levels</a>
          <a href="#research" className="mobile-nav-link">Research and Evidence</a>
          <a href="#faq" className="mobile-nav-link">FAQ</a>
          <a href="#contact" className="mobile-nav-link">Contact</a>
          <a href="#login" className="mobile-nav-link">Login</a>
        </div>
      )}
    </header>
  );
};

export default Header;
